import sys
from typing import List

class Solution:
    def solve(self, S: str, K: int) -> int:
        n = len(S)
        start = 0
        maxLen = 0
        while start < n:
            end = start + 1
            swaps = 0
            while end < n:
                if S[start] == S[end]:
                    end += 1
                else:
                    swaps += 1
                    end += 1
            if swaps <= K:
                maxLen = max(maxLen, end - start)
            start += 1
        return maxLen

def main():
    solution = Solution()
    inputs = sys.stdin.readline().split()
    S = inputs[0]
    K = int(inputs[1])
    print(solution.solve(S, K))

if __name__ == '__main__':
    main()
